// Step 2: Kategorisiere Events (kein LLM)
const rawEvents = $input.first().json;
const items = rawEvents.items || [];

if (items.length === 0) {
  return [{ json: { events: [], count: 0 } }];
}

const categorize = (title, description) => {
  const text = ((title || '') + ' ' + (description || '')).toLowerCase();
  if (/steuer|finanzamt|est|kst|ust|gewst/i.test(text)) return 'tax';
  if (/notar|grundbuch|immobilie|makler/i.test(text)) return 'real_estate';
  if (/visum|botschaft|aufenthalt|pass/i.test(text)) return 'immigration';
  if (/berater|anwalt|versicherung/i.test(text)) return 'advisory';
  if (/dba|compliance|audit/i.test(text)) return 'compliance';
  return 'personal';
};

const getEventType = (event, title) => {
  if (event.recurrence || event.recurringEventId) return 'recurring';
  if (/frist|deadline|ablauf/i.test(title || '')) return 'deadline';
  return 'appointment';
};

const events = items.map(item => {
  const startDate = item.start?.date || item.start?.dateTime?.split('T')[0];
  const endDate = item.end?.date || item.end?.dateTime?.split('T')[0];
  return {
    google_event_id: item.id,
    title: item.summary || 'Kein Titel',
    event_type: getEventType(item, item.summary),
    event_date: startDate,
    end_date: endDate,
    description: (item.description || '').substring(0, 500),
    location: item.location || null,
    category: categorize(item.summary, item.description),
    recurring: item.recurrence ? JSON.stringify(item.recurrence) : null,
    recurrence: item.recurringEventId || null,
    status: item.status === 'cancelled' ? 'cancelled' : 'upcoming',
    source: 'google_calendar',
    synced_at: new Date().toISOString(),
    warning_days: 28
  };
});

return [{ json: { events, count: events.length } }];

// Step 3: Upsert in calendar_events (Supabase)
const data = $input.first().json;
const events = data.events || [];
let inserted = 0, updated = 0, cancelled = 0;

for (const event of events) {
  // Check if event exists
  const checkResp = await fetch(
    `${$env.SUPABASE_URL}/rest/v1/calendar_events?google_event_id=eq.${event.google_event_id}&select=id,status`,
    {
      headers: {
        'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
        'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`
      },
      signal: AbortSignal.timeout(10000)
    }
  );
  const existing = await checkResp.json();

  if (Array.isArray(existing) && existing.length > 0) {
    // Update existing event
    if (event.status === 'cancelled') {
      await fetch(
        `${$env.SUPABASE_URL}/rest/v1/calendar_events?google_event_id=eq.${event.google_event_id}`,
        {
          method: 'PATCH',
          headers: {
            'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
            'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
            'Content-Type': 'application/json',
            'Prefer': 'return=minimal'
          },
          body: JSON.stringify({ status: 'cancelled', synced_at: event.synced_at }),
          signal: AbortSignal.timeout(10000)
        }
      );
      cancelled++;
    } else {
      await fetch(
        `${$env.SUPABASE_URL}/rest/v1/calendar_events?google_event_id=eq.${event.google_event_id}`,
        {
          method: 'PATCH',
          headers: {
            'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
            'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
            'Content-Type': 'application/json',
            'Prefer': 'return=minimal'
          },
          body: JSON.stringify({
            title: event.title,
            event_date: event.event_date,
            end_date: event.end_date,
            description: event.description,
            location: event.location,
            category: event.category,
            event_type: event.event_type,
            synced_at: event.synced_at
          }),
          signal: AbortSignal.timeout(10000)
        }
      );
      updated++;
    }
  } else {
    // Insert new event
    await fetch(
      `${$env.SUPABASE_URL}/rest/v1/calendar_events`,
      {
        method: 'POST',
        headers: {
          'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
          'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: JSON.stringify(event),
        signal: AbortSignal.timeout(10000)
      }
    );
    inserted++;
  }
}

return [{ json: { total: events.length, inserted, updated, cancelled } }];

// Step 4: Logger
const data = $input.first().json;
return [{ json: {
  session_id: 'calendar_sync_' + new Date().toISOString().split('T')[0],
  agent_name: 'calendar_sync',
  model: 'none',
  input_summary: `${data.total} Events geladen`,
  output_summary: `${data.inserted} neu, ${data.updated} aktualisiert, ${data.cancelled} cancelled`,
  tokens_in: 0,
  tokens_out: 0
}}];
